# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import secrets
from sqlalchemy import create_engine, Column, Integer, String, Text
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker

app = Flask(__name__)
engine = create_engine('sqlite:///users.db')
Base = declarative_base()
Session = sessionmaker(bind=engine)

class User(Base):
    __tablename__ = 'users'
    id = Column(Integer, primary_key=True)
    email = Column(String, unique=True, nullable=False)
    reset_token = Column(Text, nullable=True)

Base.metadata.create_all(engine)

@app.route('/reset_password', methods=['POST'])
def reset_password():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    session = Session()
    user = session.query(User).filter_by(email=email).first()
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    reset_token = secrets.token_urlsafe(16)
    user.reset_token = reset_token
    session.commit()
    
    # Send email with reset link (simplified for example)
    reset_link = f"http://example.com/reset?token={reset_token}"
    print(f"Send email to {email} with reset link: {reset_link}")
    
    return jsonify({'message': 'Reset email sent'}), 200

if __name__ == '__main__':
    app.run(debug=True)